mapper.select:
select
    ID as id,
    creator_employee_no as creatorEmployeeNo,
    Cost_claims_year as costClaimsYear,
    N_claims_year as nClaimsYear,
    N_claims_history as nClaimsHistory,
    R_Claims_history as rClaimsHistory,
    Type_risk as typeRisk,
    Area as area
from claim_record

    and ID = #{id}
    and creator_employee_no = #{creatorEmployeeNo}
    and Cost_claims_year = #{costClaimsYear}
    and N_claims_year = #{nClaimsYear}
    and N_claims_history = #{nClaimsHistory}
    and R_Claims_history = #{rClaimsHistory}
    and Type_risk = #{typeRisk}
    and Area = #{area}

order by ID desc
